    const st=line.match(/^- 治理状态：(.+)$/);
    if(st && cur.governance_state === null){ cur.governance_state=st[1].trim(); continue; }
    const rel=line.match(/^- 替代关系：(.+)$/);
    if(rel){
      const val=rel[1].trim(); cur.relLines.push({val,line:i+1});
      if(val === '无') continue;
      let m=val.match(/^replaces (ADR-\d{3}(?:, ADR-\d{3})*)$/);
      if(m){ cur.replaces_ids.push(...m[1].split(', ')); continue; }
      m=val.match(/^replaced-by (ADR-\d{3})$/);
      if(m){ if(cur.replaced_by_id) errors.push(`${cur.id} has duplicate replaced-by lines`); cur.replaced_by_id=m[1]; continue; }
      errors.push(`${cur.id} invalid relation syntax at line ${i+1}: ${val}`);
    }
  }
  if(cur) adrs.push(cur);
  for(const a of adrs){
    if(!a.governance_state) errors.push(`${a.id} missing governance state`);
    const hasNone=a.relLines.some(r=>r.val==='无');
    if(hasNone && a.relLines.length>1) errors.push(`${a.id} mixes relation none with other relation lines`);
    const repLineCount=a.relLines.filter(r=>r.val.startsWith('replaces ')).length;
    const rbLineCount=a.relLines.filter(r=>r.val.startsWith('replaced-by ')).length;
    if(repLineCount>1) errors.push(`${a.id} has duplicate replaces lines`);
    if(rbLineCount>1) errors.push(`${a.id} has duplicate replaced-by lines`);
    const unique=[...new Set(a.replaces_ids)];
    if(unique.length!==a.replaces_ids.length) errors.push(`${a.id} has duplicate replaces targets`);
    a.replaces_ids=unique;
  }
  return {adrs, errors};
}
function validate(adrs, parseErrors){
  const errors=[...parseErrors]; const by=new Map(adrs.map(a=>[a.id,a])); const edges=[];
  for(const a of adrs){
    for(const old of a.replaces_ids){
      if(!by.has(old)) errors.push(`${a.id} replaces missing target ${old}`);
      if(old===a.id) errors.push(`${a.id} self replacement`);
      edges.push({old, newer:a.id, source:'replaces'});
    }
    if(a.replaced_by_id){
      if(!by.has(a.replaced_by_id)) errors.push(`${a.id} replaced-by missing target ${a.replaced_by_id}`);
      if(a.replaced_by_id===a.id) errors.push(`${a.id} self replacement`);
      edges.push({old:a.id, newer:a.replaced_by_id, source:'replaced-by'});
    }
  }
  const edgeKeys = new Set(edges.map(e=>`${e.old}->${e.newer}`));
  for(const e of [...edgeKeys].map(k=>{const [old,newer]=k.split('->'); return {old,newer};})){
    const oldA=by.get(e.old), newA=by.get(e.newer);
    if(oldA && newA){
      if(!(newA.replaces_ids||[]).includes(e.old)) errors.push(`unilateral/mismatched relation: ${e.old}->${e.newer} lacks ${e.newer} replaces ${e.old}`);
      if(oldA.replaced_by_id !== e.newer) errors.push(`unilateral/mismatched relation: ${e.old}->${e.newer} lacks ${e.old} replaced-by ${e.newer}`);
      if(oldA.governance_state !== '已替代') errors.push(`${e.old} is replaced by ${e.newer} but state is ${oldA.governance_state}`);
    }
  }
  for(const a of adrs){
    if(a.replaced_by_id && a.governance_state !== '已替代') errors.push(`${a.id} has replaced-by but state is ${a.governance_state}`);
    if(a.governance_state === '已替代' && !a.replaced_by_id) errors.push(`${a.id} state 已替代 but has no replaced-by`);
  }
  const adj=new Map(); for(const k of edgeKeys){ const [o,n]=k.split('->'); if(by.has(o)&&by.has(n)){ if(!adj.has(o)) adj.set(o,[]); adj.get(o).push(n); }}
  const visiting=new Set(), visited=new Set(), stack=[]; const cycles=[];
  function dfs(n){
    if(visiting.has(n)){ const idx=stack.indexOf(n); cycles.push([...stack.slice(idx), n].join(' -> ')); return; }
    if(visited.has(n)) return; visiting.add(n); stack.push(n);
    for(const m of adj.get(n)||[]) dfs(m);
    stack.pop(); visiting.delete(n); visited.add(n);
  }
  for(const id of by.keys()) dfs(id);
  for(const c of cycles) errors.push(`replacement cycle: ${c}`);
  return {errors:[...new Set(errors)], edges:[...edgeKeys].sort()};
