    m=line.match(/^- Goal:\s*(.+)$/); if(m) compact.goal=m[1].trim();
    m=line.match(/^- Key constraints:\s*(.+)$/); if(m) compact.key_constraints=m[1].trim();
    m=line.match(/^- Completed:\s*(.+)$/); if(m) compact.completed=m[1].trim();
    m=line.match(/^- Next:\s*(.+)$/); if(m) compact.next=m[1].trim();
    m=line.match(/^- Blockers:\s*(.+)$/); if(m) compact.blockers=m[1].trim();
    m=line.match(/^- Related active decisions:\s*(.+)$/); if(m) compact.related_active_decisions=idsFrom(m[1]).sort();
  }
